import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    best_node = None
    min_time = float('inf')

    for i, customer in enumerate(unvisited_customers):
        travel_time = np.linalg.norm(cur_truck_pos - customer) / truck_speed
        earliest_time = max(current_time + travel_time, time_windows[i][0])
        latest_time = time_windows[i][1]

        if latest_time >= earliest_time:
            expected_time = max(latest_time, current_time + travel_time)
        else:
            expected_time = latest_time + (earliest_time - latest_time) + travel_time

        if expected_time < min_time:
            min_time = expected_time
            best_node = i

    return best_node
